return [{
  json: {
    source: 'employee_chat',
    employee: {
      name: 'Sarah Chen',
      id: 'EMP_4821',
      department: 'Sales',
      level: 'manager'
    },
    request: 'I need to schedule onboarding for our new hire starting Monday, book conference room B for the team meeting tomorrow at 2pm, and submit my expense report for the SF trip',
    detectedIntents: ['hr_onboarding', 'room_booking', 'expense_submission'],
    complexity: 'multi_domain'
  }
}];

const req = $input.first().json;

// Avaamo's Agentic AI routes to appropriate skill/agent
const skills = {
  hr_onboarding: {
    name: 'HR Onboarding Agent',
    capabilities: ['create_onboarding_plan', 'schedule_orientation', 'provision_accounts', 'notify_mentor'],
    autonomy: 'high', // Can execute without approval
    systems: ['workday', 'active_directory', 'slack']
  },
  room_booking: {
    name: 'Workspace Agent',
    capabilities: ['check_availability', 'book_room', 'order_catering', 'send_invites'],
    autonomy: 'high',
    systems: ['condeco', 'outlook', 'zoom']
  },
  expense_submission: {
    name: 'Finance Agent',
    capabilities: ['parse_receipts', 'categorize_expenses', 'check_policy', 'submit_for_approval'],
    autonomy: 'medium', // Requires manager approval if over limit
    systems: ['expensify', 'sap', 'email']
  },
  it_support: {
    name: 'IT Helpdesk Agent',
    capabilities: ['password_reset', 'access_provisioning', 'ticket_creation', 'auto_resolution'],
    autonomy: 'high',
    systems: ['servicenow', 'active_directory', 'slack']
  },
  sales_assist: {
    name: 'Sales Copilot',
    capabilities: ['research_prospect', 'draft_email', 'update_crm', 'schedule_meeting'],
    autonomy: 'low', // Requires sales rep review
    systems: ['salesforce', 'linkedin', 'gmail', 'calendar']
  }
};

// Route to appropriate skills
const activatedSkills = req.detectedIntents.map(intent => ({
  intent,
  skill: skills[intent],
  confidence: 0.95
}));

// Determine if any need human approval
const requiresApproval = activatedSkills.some(s => s.skill.autonomy === 'low') || 
                         activatedSkills.filter(s => s.skill.autonomy === 'medium').length > 1;

return [{
  json: {
    ...req,
    activatedSkills,
    requiresApproval,
    canAutoExecute: !requiresApproval && activatedSkills.every(s => s.skill.autonomy === 'high'),
    estimatedCompletion: activatedSkills.length * 2 + ' minutes'
  }
}];

// Execute HR Onboarding
return [{
  json: {
    skill: 'hr_onboarding',
    actions: [
      { action: 'create_onboarding_plan', status: 'completed', output: '5-day plan created' },
      { action: 'schedule_orientation', status: 'completed', output: 'Mon 9am with HR' },
      { action: 'provision_accounts', status: 'completed', output: 'Email, Slack, Salesforce ready' },
      { action: 'notify_mentor', status: 'completed', output: 'Mentor assigned: John Smith' }
    ],
    newHire: {
      name: 'Alex Johnson',
      startDate: '2026-03-03',
      role: 'Sales Development Rep'
    }
  }
}];

// Execute Room Booking
return [{
  json: {
    skill: 'room_booking',
    actions: [
      { action: 'check_availability', status: 'completed', output: 'Room B available' },
      { action: 'book_room', status: 'completed', output: 'Thu 2pm-3pm confirmed' },
      { action: 'order_catering', status: 'completed', output: 'Coffee & snacks ordered' },
      { action: 'send_invites', status: 'completed', output: '12 invites sent' }
    ],
    booking: {
      room: 'Conference Room B',
      date: '2026-02-28',
      time: '14:00-15:00',
      attendees: 12
    }
  }
}];

// Execute Expense Submission
const expenses = [
  { category: 'Travel', amount: 450, receipt: 'attached', policyCompliant: true },
  { category: 'Meals', amount: 85, receipt: 'attached', policyCompliant: true },
  { category: 'Lodging', amount: 320, receipt: 'attached', policyCompliant: true }
];
const total = expenses.reduce((sum, e) => sum + e.amount, 0);
const needsManagerApproval = total > 500;

return [{
  json: {
    skill: 'expense_submission',
    actions: [
      { action: 'parse_receipts', status: 'completed', output: '3 receipts processed' },
      { action: 'categorize_expenses', status: 'completed', output: 'Travel, Meals, Lodging' },
      { action: 'check_policy', status: 'completed', output: 'All compliant' },
      { action: 'submit_for_approval', status: needsManagerApproval ? 'pending' : 'completed', output: needsManagerApproval ? 'Awaiting manager approval' : 'Auto-approved' }
    ],
    expenseReport: {
      id: 'EXP-2026-' + Date.now().toString().slice(-4),
      total: total,
      items: expenses.length,
      status: needsManagerApproval ? 'pending_approval' : 'approved'
    }
  }
}];

// Aggregate results from all agents
const results = $input.all().map(item => item.json);
const mainRequest = $item(0).$node[

].json;

const summary = {
  request: mainRequest.request,
  employee: mainRequest.employee.name,
  skillsActivated: results.length,
  completedActions: results.reduce((sum, r) => sum + r.actions.filter(a => a.status === 'completed').length, 0),
  pendingActions: results.reduce((sum, r) => sum + r.actions.filter(a => a.status === 'pending').length, 0),
  details: results.map(r => ({
    skill: r.skill,
    summary: r.actions.map(a => a.action).join(', ')
  }))
};

return [{
  json: summary
}];
